```javascript
function solve(code, businessLine, isActive) {
  const validCodes = [];
  const businessOrder = {
    "electronics": 0,
    "grocery": 1,
    "pharmacy": 2,
    "restaurant": 3
  };

  for (let i = 0; i < code.length; i++) {
    const c = code[i];
    const bl = businessLine[i];
    const active = isActive[i];

    // Check code validity
    if (c === "" || !/^[a-zA-Z0-9_]+$/.test(c)) {
      continue;
    }

    // Check business line
    if (!["electronics", "grocery", "pharmacy", "restaurant"].includes(bl)) {
      continue;
    }

    // Check active
    if (!active) {
      continue;
    }

    validCodes.push({ code: c, businessLine: bl });
  }

  // Sort the valid codes
  validCodes.sort((a, b) => {
    const orderA = businessOrder[a.businessLine];
    const orderB = businessOrder[b.businessLine];
    if (orderA !== orderB) {
      return orderA - orderB;
    }
    return a.code.localeCompare(b.code);
  });

  return validCodes.map(c => c.code);
}
```

